class Solution:
    def findMaxVal(self, n, restrictions, diff):
        # Independent check via explicit reachable-value-set enumeration (BFS over
        # actual integers) rather than the closed-form bound-propagation formula.
        # Only used at small n by the harness's stress/edge sizing.
        cap = {}
        for idx, maxVal in restrictions:
            cap[idx] = maxVal
        reach = [set() for _ in range(n)]
        reach[0] = {0}
        for i in range(1, n):
            prev = reach[i - 1]
            d = diff[i - 1]
            nxt = set()
            for v in prev:
                for delta in range(-d, d + 1):
                    nv = v + delta
                    if nv >= 0:
                        nxt.add(nv)
            if i in cap:
                nxt = {v for v in nxt if v <= cap[i]}
            reach[i] = nxt
        # Backward feasibility filter: keep only values from which every later
        # step can still be legally completed to the end of the sequence.
        feasible = [None] * n
        feasible[n - 1] = reach[n - 1]
        for i in range(n - 2, -1, -1):
            d = diff[i]
            nxt_feasible = feasible[i + 1]
            kept = set()
            for v in reach[i]:
                for nv in nxt_feasible:
                    if abs(v - nv) <= d:
                        kept.add(v)
                        break
            feasible[i] = kept
        best = 0
        for s in feasible:
            if s:
                best = max(best, max(s))
        return best

