class Solution:
    def findMaxVal(self, n, restrictions, diff):
        bound = [0] * n
        for i in range(1, n):
            bound[i] = bound[i - 1] + diff[i - 1]
        for idx, maxVal in restrictions:
            if maxVal < bound[idx]:
                bound[idx] = maxVal
        for i in range(1, n):
            candidate = bound[i - 1] + diff[i - 1]
            if candidate < bound[i]:
                bound[i] = candidate
        for i in range(n - 2, -1, -1):
            candidate = bound[i + 1] + diff[i]
            if candidate < bound[i]:
                bound[i] = candidate
        return max(bound)

