var findMaxVal = function(n, restrictions, diff) {
    const bound = new Array(n).fill(0);
    for (let i = 1; i < n; i++) {
        bound[i] = bound[i - 1] + diff[i - 1];
    }
    for (const [idx, maxVal] of restrictions) {
        if (maxVal < bound[idx]) bound[idx] = maxVal;
    }
    for (let i = 1; i < n; i++) {
        const candidate = bound[i - 1] + diff[i - 1];
        if (candidate < bound[i]) bound[i] = candidate;
    }
    for (let i = n - 2; i >= 0; i--) {
        const candidate = bound[i + 1] + diff[i];
        if (candidate < bound[i]) bound[i] = candidate;
    }
    let best = 0;
    for (let i = 0; i < n; i++) {
        if (bound[i] > best) best = bound[i];
    }
    return best;
};
